// Lead-Validierung und Scoring
const lead = $input.first().json;
const email = lead.email?.toLowerCase().trim();
const tag = lead.tag || 'unknown';
const firstName = lead.first_name || 'Interessent';

// Einfache Validierung
const isValid = email && email.includes('@') && email.includes('.');

// Lead-Score basierend auf Tag
const scoreMap = {
  '05-lead-generation-pkv': 100,
  '04-ki-integrationen-35plus': 90,
  '07-marketing-agency-traffic': 85,
  '09-finanzielle-freiheit': 80,
  '01-affiliate-marketing': 60,
  '03-pdfs-guides': 50,
  '08-app-ideen-appstore': 55,
  '11-immobilien-baufinanzierung': 75,
  '10-gesundheit-praevention-40plus': 65,
  '12-selbststaendigkeit-business-setup': 70,
  '06-lead-generation-dropshipping': 45,
  '02-tiktok-shop': 40,
  '13-reisen-lifestyle-35plus': 35,
  '14-nachhaltigkeit-eco': 35
};

return [{
  json: {
    email,
    firstName,
    tag,
    isValid,
    score: scoreMap[tag] || 30,
    source: lead.source || 'landing-page',
    createdAt: new Date().toISOString()
  }
}];

